import{_ as e,c as r,o as a,a as t}from"./app.8bfa11d3.js";const w=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[{"level":2,"title":"一、了解考试内容","slug":"一、了解考试内容","link":"#一、了解考试内容","children":[]},{"level":2,"title":"二、有哪些复习资料？","slug":"二、有哪些复习资料","link":"#二、有哪些复习资料","children":[]},{"level":2,"title":"三、国考省考有什么区别？","slug":"三、国考省考有什么区别","link":"#三、国考省考有什么区别","children":[]},{"level":2,"title":"国考和省考，福利待遇、发展前景哪个更好？","slug":"国考和省考-福利待遇、发展前景哪个更好","link":"#国考和省考-福利待遇、发展前景哪个更好","children":[{"level":3,"title":"国考公务员江苏上岸和江苏省考公务员上岸薪资待遇一样吗？","slug":"国考公务员江苏上岸和江苏省考公务员上岸薪资待遇一样吗","link":"#国考公务员江苏上岸和江苏省考公务员上岸薪资待遇一样吗","children":[]}]},{"level":2,"title":"如何找合适的岗位","slug":"如何找合适的岗位","link":"#如何找合适的岗位","children":[{"level":3,"title":"公考雷达app","slug":"公考雷达app","link":"#公考雷达app","children":[]},{"level":3,"title":"官方网站","slug":"官方网站","link":"#官方网站","children":[]},{"level":3,"title":"培训机构网站查询","slug":"培训机构网站查询","link":"#培训机构网站查询","children":[]},{"level":3,"title":"职场公众号、头条号","slug":"职场公众号、头条号","link":"#职场公众号、头条号","children":[]}]},{"level":2,"title":"国考专业大类","slug":"国考专业大类","link":"#国考专业大类","children":[]},{"level":2,"title":"江苏省省考专业所属大类","slug":"江苏省省考专业所属大类","link":"#江苏省省考专业所属大类","children":[]},{"level":2,"title":"江苏省省考报名时间","slug":"江苏省省考报名时间","link":"#江苏省省考报名时间","children":[{"level":3,"title":"报名时间：11月8 日9∶00至11月14日16∶00","slug":"报名时间-11月8-日9∶00至11月14日16∶00","link":"#报名时间-11月8-日9∶00至11月14日16∶00","children":[]},{"level":3,"title":"笔试时间：12月17至18日","slug":"笔试时间-12月17至18日","link":"#笔试时间-12月17至18日","children":[]},{"level":3,"title":"面试时间：2023年3月上旬","slug":"面试时间-2023年3月上旬","link":"#面试时间-2023年3月上旬","children":[]}]},{"level":2,"title":"国考时间","slug":"国考时间","link":"#国考时间","children":[]},{"level":2,"title":"一个月冲刺国考","slug":"一个月冲刺国考","link":"#一个月冲刺国考","children":[]},{"level":2,"title":"私企上班算基层工作经验吗","slug":"私企上班算基层工作经验吗","link":"#私企上班算基层工作经验吗","children":[]},{"level":2,"title":"国考税务局","slug":"国考税务局","link":"#国考税务局","children":[]},{"level":2,"title":"省直、市直、区直","slug":"省直、市直、区直","link":"#省直、市直、区直","children":[]}],"relativePath":"6.其他/考公/起步.md","lastUpdated":1694759414000}'),h={name:"6.其他/考公/起步.md"},l=t('<blockquote><p><a href="https://www.zhihu.com/question/42155091" target="_blank" rel="noreferrer">https://www.zhihu.com/question/42155091</a></p></blockquote><h2 id="一、了解考试内容" tabindex="-1">一、了解考试内容 <a class="header-anchor" href="#一、了解考试内容" aria-hidden="true">#</a></h2><p>简单的说考试分为笔试、面试和体检政审。</p><p>笔试是考《行政能力测验》和《申论》。</p><p>《行测》考的都是能力方面，你的言语理解能力、资料分析能力、逻辑思维能力、数学运算能力、常识掌握能力等。在考试中你几乎看不到任何曾经见过的题，但知识点是相同。</p><p>《申论》考的是你的写作能力，细化可以分成对文章的总结能力、对问题的分析能力、对策略观点的提出能力以及文字综合能力。相比行测，申论更为枯燥，但提分更快，因为技巧性更强。 一般情况下考完一个月左右出成绩及其面试名单，面试比例常见1：3或者1：5，即每个岗位的前三名或者前五名进入面试。</p><h2 id="二、有哪些复习资料" tabindex="-1">二、有哪些复习资料？ <a class="header-anchor" href="#二、有哪些复习资料" aria-hidden="true">#</a></h2><p>其实我感觉看大本纸质教材是非常枯燥的，不如直接看视频来的直接，毕竟那是别人总结来的技巧，我们直接拿来运用即可，但是问题是很多刚开始接触公考的小白没有基础，可能直接看视频吸收不了，所以这里还是建议大家看看一些书籍教材打一下基础。这里给大家推荐几本还不错的书籍。</p><h2 id="三、国考省考有什么区别" tabindex="-1">三、国考省考有什么区别？ <a class="header-anchor" href="#三、国考省考有什么区别" aria-hidden="true">#</a></h2><p>考试的内容都是一样的，其中省考以国考为风向标，一般情况下每年分别一次。都是考《行政能力测验》和《申论》。但是，有的乡镇考试不一样，只考其中一项，具体看报考单位。所以大家安心学习申论跟行测，不管是省考还是国考都是适用的。下面我们说说不一样的地方：</p><p>1、考试时间不同：以往年的考试时间来看，国考一般是在当年的10月份后发布公告，省考是在4.20左右报名</p><p>2、用人单位的不同：国考是中央级别的单位还有就是中央机关在各地的直属机构。省考用人单位是地方的党委、人大、政府检察院等</p><p>3、省考分为联考和各地单独招考：何为联考？联考就是多省同一天考试。各地单独招考是乡镇的事业单位考试。 以往年的经验来看参加联考的省份有：吉林、山西、云南、江西、陕西、重庆、天津、宁夏、湖北、甘肃、河北、安徽、湖南、福建、海南、黑龙江、四川（省考）、贵州、广西、青海、新疆、内蒙古。</p><p>不参加联考的省份：江苏、广东、广州、浙江、北京、上海、深圳。注意：每年省份是否参加联考取决于各个省，不是每年都是固定的。 自主命题的省份和其他考试（国考+联考）有不同，比如：江苏省考重点是事例性材料，上海市考和北京市考经常要结合多则材料进行作答。广东和深圳的考试对于大作文方面有文体要求。但是不管怎么变化，其实基础知识不变。</p><h2 id="国考和省考-福利待遇、发展前景哪个更好" tabindex="-1">国考和省考，福利待遇、发展前景哪个更好？ <a class="header-anchor" href="#国考和省考-福利待遇、发展前景哪个更好" aria-hidden="true">#</a></h2><blockquote><p><a href="http://www.jsgwyw.org/2022/0810/97429.html" target="_blank" rel="noreferrer">http://www.jsgwyw.org/2022/0810/97429.html</a></p></blockquote><h3 id="国考公务员江苏上岸和江苏省考公务员上岸薪资待遇一样吗" tabindex="-1">国考公务员江苏上岸和江苏省考公务员上岸薪资待遇一样吗？ <a class="header-anchor" href="#国考公务员江苏上岸和江苏省考公务员上岸薪资待遇一样吗" aria-hidden="true">#</a></h3><blockquote><p><a href="https://www.zhihu.com/question/407705922" target="_blank" rel="noreferrer">https://www.zhihu.com/question/407705922</a></p></blockquote><h2 id="如何找合适的岗位" tabindex="-1">如何找合适的岗位 <a class="header-anchor" href="#如何找合适的岗位" aria-hidden="true">#</a></h2><h3 id="公考雷达app" tabindex="-1">公考雷达app <a class="header-anchor" href="#公考雷达app" aria-hidden="true">#</a></h3><blockquote><p><a href="https://www.zhihu.com/question/411135901" target="_blank" rel="noreferrer">https://www.zhihu.com/question/411135901</a></p></blockquote><p>可能存在一定延误性</p><h3 id="官方网站" tabindex="-1">官方网站 <a class="header-anchor" href="#官方网站" aria-hidden="true">#</a></h3><p>公务员招考一般分为国考和省考。</p><p>1.国考一般由<a href="https://www.gwy.com/gjgwy/" target="_blank" rel="noreferrer">国家公务员</a>局发布，考生可以登陆中央机关及其直属机构考试录用公务员专题网站（<a href="http://bm.scs.gov.cn/kl2023%EF%BC%89%E6%9F%A5%E9%98%85%E3%80%82" target="_blank" rel="noreferrer">http://bm.scs.gov.cn/kl2023）查阅。</a></p><p>2.省考一般由各省、市人力资源和社会保障局官方网站发布，这是最权威出处，重点把握好每年3-4月，8-9月时间段。其中公务员招聘信息一般省、市两级网站都会公告，<a href="https://www.gwy.com/sydw/" target="_blank" rel="noreferrer">事业单位</a>要区分级别，省属事业单位的一般从省级网站查询，市属、区属事业单位信息可以在市级网站查询。</p><blockquote><p><a href="https://www.zhihu.com/question/44539564" target="_blank" rel="noreferrer">https://www.zhihu.com/question/44539564</a></p><p>江苏省职位2023职位 <a href="http://jshrss.jiangsu.gov.cn/art/2022/11/4/art_87129_10651696.html" target="_blank" rel="noreferrer">http://jshrss.jiangsu.gov.cn/art/2022/11/4/art_87129_10651696.html</a></p></blockquote><h3 id="培训机构网站查询" tabindex="-1">培训机构网站查询 <a class="header-anchor" href="#培训机构网站查询" aria-hidden="true">#</a></h3><p>有人可能会觉得这么看有些麻烦，其实想获取全面的信息也很简单，你只要登录培训机构网站查询就好了，那些大型的培训机构，网站会综合全国的公务员和事业编制考试信息，查询起来轻松简单。公务员招聘信息，还有银行、信用社等等，总之涉及到国家财政发工资的招聘信息都有。</p><h3 id="职场公众号、头条号" tabindex="-1">职场公众号、头条号 <a class="header-anchor" href="#职场公众号、头条号" aria-hidden="true">#</a></h3><p>关注微信头条及微信公众号，他们会第一时间转发相关信息和岗位。现在来说，无论是私企网站还是政府网站，都会有自己的公众号，只要关注了这些公众号，基本上只要有招聘信息，他们就会给你进行推送。对于一些大型国企的公众号，也可以关注，这样</p><h2 id="国考专业大类" tabindex="-1">国考专业大类 <a class="header-anchor" href="#国考专业大类" aria-hidden="true">#</a></h2><p>国考和省考专业所属大类可能不同，比如说物联网工程专业，国考属于<strong>计算机类</strong>，省考则属于更细分的<strong>计算机（网络管理）类</strong>，而不属于<strong>计算机类</strong></p><blockquote><p>国考专业大类参考 <a href="https://www.chinagwy.org/html/kszc/gj/202210/42_543871.html" target="_blank" rel="noreferrer">https://www.chinagwy.org/html/kszc/gj/202210/42_543871.html</a></p></blockquote><h2 id="江苏省省考专业所属大类" tabindex="-1">江苏省省考专业所属大类 <a class="header-anchor" href="#江苏省省考专业所属大类" aria-hidden="true">#</a></h2><p>比如说物联网工程属于<strong>计算机（网络管理）类</strong>，不属于<strong>计算机类</strong>，不能报考<strong>计算机类</strong>的岗位</p><blockquote><p>2021年度江苏省考试录用公务员专业参考目录 <a href="http://www.jsgwyw.org/2020/1030/75346.html" target="_blank" rel="noreferrer">http://www.jsgwyw.org/2020/1030/75346.html</a></p><p>江苏省2023年度考试录用公务员专业参考目录 <a href="http://www.jszzb.gov.cn/col95/83203.html" target="_blank" rel="noreferrer">http://www.jszzb.gov.cn/col95/83203.html</a></p></blockquote><h2 id="江苏省省考报名时间" tabindex="-1">江苏省省考报名时间 <a class="header-anchor" href="#江苏省省考报名时间" aria-hidden="true">#</a></h2><p>以2023年江苏省公务员为参考，具体时间看官网说明</p><h3 id="报名时间-11月8-日9∶00至11月14日16∶00" tabindex="-1">报名时间：<strong>11月8 日9∶00至11月14日16∶00</strong> <a class="header-anchor" href="#报名时间-11月8-日9∶00至11月14日16∶00" aria-hidden="true">#</a></h3><p>资格初审时间：2022年11月8 日9∶00至11月16日16∶00</p><p>缴费时间：2022年11月8日9∶00至11月17日16∶00</p><p>报考者在全省范围内只能选择一个职位报名，并在报考职位所在考区参加笔试，全省特殊专技职位统一在省直考区（南京）参加笔试。2022年11月8日9∶00至11月14日16∶00期间，报考者报考资格未经初审或者初审未通过的，可以改报其他职位；2022年11月14日16∶00至11月16日16∶00期间，报考者报考资格未经初审或者初审未通过的，不能再更改报名信息，也不能再改报其他职位；报名时必须使用在有效期内的二代身份证。</p><h3 id="笔试时间-12月17至18日" tabindex="-1">笔试时间：12月17至18日 <a class="header-anchor" href="#笔试时间-12月17至18日" aria-hidden="true">#</a></h3><p>公共科目笔试时间为<strong>2022年12月17日</strong>，具体安排为：</p><p>上午9∶00－11∶00行政职业能力测验</p><p>下午14∶00－16∶30申论</p><p>公安专业科目笔试时间为<strong>2022年12月18日</strong>，具体安排为：</p><p>上午9∶00－11∶00</p><p>成功报名的人员，要根据准考证上的时间和地点参加考试，参加笔试考试时需要携带准考证和身份证，身份证必须和报名时的身份证信息一致。</p><h3 id="面试时间-2023年3月上旬" tabindex="-1">面试时间：2023年3月上旬 <a class="header-anchor" href="#面试时间-2023年3月上旬" aria-hidden="true">#</a></h3><p>根据官方的规定，2023年江苏省<a href="https://www.gwy.com/gjgwy/msxx/" target="_blank" rel="noreferrer">公务员面试</a>拟于<strong>2023年3月上旬</strong>举行，具体的面试日期还没有确定。而且如果遇到疫情，面试时间可能会延迟。所以具体的面试时间届时要以官方通知为准。</p><p>以上就是关于2023江苏省公务员考试时间的安排，大家首先要为笔试做好准备，要抓紧时间复习，争取在笔试中取得自己满意的成绩，才有机会进入面试。</p><h2 id="国考时间" tabindex="-1">国考时间 <a class="header-anchor" href="#国考时间" aria-hidden="true">#</a></h2><p>近10年来，国考时间安排较规律，2012~2023年几乎都是10月发布公告，报名时间也差不多</p><p>2024年报名考试的话，参考2023年</p><p>2023年国家公务员考试将于2022年10月25日8:00至11月3日18:00期间报名。</p><p>2023年1月7日至8日举行笔试。</p><p>3月15日，中央机关及其直属机构2023年度考试录用公务员笔试成绩和合格分数线公布</p><h2 id="一个月冲刺国考" tabindex="-1">一个月冲刺国考 <a class="header-anchor" href="#一个月冲刺国考" aria-hidden="true">#</a></h2><blockquote><p><a href="https://www.zhihu.com/question/341541048" target="_blank" rel="noreferrer">https://www.zhihu.com/question/341541048</a></p></blockquote><h2 id="私企上班算基层工作经验吗" tabindex="-1">私企上班算基层工作经验吗 <a class="header-anchor" href="#私企上班算基层工作经验吗" aria-hidden="true">#</a></h2><p>算。</p><p>基层工作经历指的是具有在县级及以下<strong>党政机关、国有企事业单位、村（社区）组织及其他经济组织、社会组织</strong>等工作的经历，社会组织就包含了私企，所以，<strong>在私企工作也算是工作基层经历。</strong></p><h2 id="国考税务局" tabindex="-1">国考税务局 <a class="header-anchor" href="#国考税务局" aria-hidden="true">#</a></h2><p>税务局作为国考之中招考人数最多也是报考人数最多的部门之一，考试科目分为两大类，申论和行测。</p><p>国考中，申论总共150分，是材料写作题，具有很大的主观性，主要考察应考人员对给定材料的分析、概括、提炼、加工，测查应考人员的阅读理解能力、综合分析能力、提出问题和解决问题能力、文字表达能力等。</p><p>国考行测向来是最难的点。行测每年均考查固定的五大类题型：<strong>常识判断、言语理解与表达、数量关系、判断推理、资料分析</strong>。</p><h2 id="省直、市直、区直" tabindex="-1">省直、市直、区直 <a class="header-anchor" href="#省直、市直、区直" aria-hidden="true">#</a></h2>',69),n=[l];function i(s,o,p,d,c,g){return a(),r("div",null,n)}const k=e(h,[["render",i]]);export{w as __pageData,k as default};
